import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists(): return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

ORIGINAL = {
"34": {
"1": "<p>YHWH commands Moses to give Israel the precise borders of the land before entry. The land is not undefined space — it is a named, bounded inheritance (<em>nachalah</em>) with specific geography. God had promised Abraham 'this land' (Gen 15:18); now he delivers coordinates.</p>",
"2": "<p>'Command the Israelites and say: when you enter the land of Canaan, this is the land that shall fall to you as inheritance (<em>nachalah</em>), the land of Canaan according to its borders (<em>gevuloteha</em>).' <em>Gevul</em> (border, boundary) frames all that follows — the gift has edges, which means the gift is real and specific, not merely symbolic.</p>",
"3": "<p>The southern boundary begins at the wilderness of Zin along the border of Edom. The south is defined by known terrain — Zin (the desert where Miriam died, ch20) and Edom (the nation that refused passage, ch20:14-21). Even hostile terrain becomes a boundary marker for God's gift.</p>",
"4": "<p>The border turns from the south of the Ascent of Akrabbim, passes through Zin, and its limit shall be south of Kadesh-barnea. Kadesh — where the spies reported and the people rebelled (ch13-14) — now marks a corner of the inheritance. The place of failure becomes a border post of the promised land.</p>",
"5": "<p>From Kadesh-barnea it goes to Hazar-addar and continues to Azmon. The specificity is remarkable — these are not approximations but demarcated points, suggesting a real administrative boundary Israel was expected to recognize and maintain.</p>",
"6": "<p>The western boundary (<em>yam</em>, sea) is simply 'the Great Sea' — the Mediterranean. The sea itself is the boundary, natural and absolute. Israel is not a seafaring nation in the Mosaic vision; the horizon of the sea marks the western limit of the inheritance.</p>",
"7": "<p>The northern boundary: from the Great Sea to Mount Hor. This Hor is different from the Hor in Edom where Aaron died (ch20:22) — geographical terminology reused for a different location, a reminder that names recur in Scripture without always denoting the same place.</p>",
"8": "<p>From Mount Hor to Lebo-hamath. Lebo-hamath ('entrance of Hamath') marks the northern gateway into Aramean territory. This boundary anticipates the later Davidic empire's extent; it is the promise in geographic form.</p>",
"9": "<p>The boundary ends at Zedad, then continues to Ziphron, and its limit shall be Hazar-enan. These northern points anchor the promise in real geography, known to ancient Near Eastern cartographers though obscure to modern readers.</p>",
"10": "<p>The eastern boundary from Hazar-enan to Shepham. The east side of the promised land runs through territory contested between Aram and Israel in later centuries. The boundary is not merely legal — it is eschatological, projecting what Israel's inheritance should ultimately encompass.</p>",
"11": "<p>From Shepham the border descends to Riblah on the east side of Ain, then down to the shoulder of the Sea of Chinnereth (the Sea of Galilee). Riblah reappears in Jeremiah as the site of Judah's judgment (Jer 39:5-6) — the same points that mark the promised inheritance later mark exile.</p>",
"12": "<p>The border continues down the Jordan and ends at the Salt Sea (Dead Sea). 'This is the land with its borders all around.' The Jordan, from Galilee to the Dead Sea, forms the eastern boundary. The river that Israel crossed miraculously (Josh 3) becomes the permanent eastern marker of the inheritance.</p>",
"13": "<p>Moses commands: 'This is the land you shall apportion by lot among yourselves, which YHWH has commanded to give to nine and a half tribes.' <em>Goral</em> (lot) signals divine sovereignty — the size of each tribe's portion is ultimately God's determination, not human negotiation. Lot-casting in the Ancient Near East was understood as divine decision.</p>",
"14": "<p>Reuben, Gad, and the half-tribe of Manasseh have received their inheritance east of the Jordan already (ch32). Their decision to settle Transjordan, born of pragmatism (good pastureland), means they receive outside the boundaries just described. The Transjordanian tribes exist in a kind of borderland status throughout Israel's history.</p>",
"15": "<p>Two and a half tribes received east of the Jordan at Jericho, toward the sunrise. 'Toward the sunrise' (<em>mizrach hashemesh</em>) — the east, the direction of dawn, frames the Transjordanian settlement not as inferior but as oriented toward light. Yet the full promise of Canaan remained west of the Jordan.</p>",
"16": "<p>YHWH speaks: 'These are the names of the men who shall apportion the land among you.' The process of inheritance distribution is not improvised — YHWH designates specific leaders. The land-gift comes with administrative structure, not chaos.</p>",
"17": "<p>Eleazar the priest and Joshua son of Nun will lead the apportionment. The pairing is significant: priestly authority (Eleazar) and military-civil authority (Joshua) together manage the inheritance. Neither alone — sacred and civil together serve the distribution of God's gift.</p>",
"18": "<p>One leader from each tribe shall be appointed to apportion the land. The process is tribal, representative, and inclusive. Every tribe has a voice in receiving what God promised their ancestor.</p>",
"19": "<p>From the tribe of Judah: Caleb son of Jephunneh. Caleb survives from the spy generation (ch13-14) specifically because he 'followed YHWH wholeheartedly' (14:24). His presence here as Judah's representative is a quiet vindication — the faithful outlast the unfaithful.</p>",
"20": "<p>From Simeon: Shemuel son of Ammihud. Simeon's tribe would later be absorbed largely into Judah (Josh 19:1), receiving no distinct territory. Yet here they stand equally in the apportionment process — the future diminishment is not yet written.</p>",
"21": "<p>From Benjamin: Elidad son of Kislon. Benjamin's territory would later contain Jerusalem (on its border with Judah) and Saul's hometown, Gibeah. The small tribe with large significance.</p>",
"22": "<p>From the tribe of Dan: Bukki son of Jogli. Dan's territory would prove difficult to hold — the tribe would eventually migrate north (Judg 18), partly explaining why Dan is absent from the tribal listing in Revelation 7.</p>",
"23": "<p>From Manasseh (the half-tribe west of Jordan): Hanniel son of Ephod. The full tribe of Manasseh is split — half east (already settled, v14-15) and half west (still to be apportioned). Hanniel represents the western half.</p>",
"24": "<p>From Ephraim: Kemuel son of Shiphtan. Ephraim — the younger son whom Jacob blessed ahead of Manasseh (Gen 48) — receives the larger territory in the central highlands and gives the region its central significance.</p>",
"25": "<p>From Zebulun: Elizaphan son of Parnach. Zebulun's territory in the Galilee region would become notable in Isaiah's 'land of Zebulun' prophecy (Isa 9:1) and its fulfillment in Jesus's Galilean ministry (Matt 4:13-16).</p>",
"26": "<p>From Issachar: Paltiel son of Azzan. Issachar settles in the Jezreel Valley — fertile agricultural land. The tribe is later characterized as 'understanding the times' (1 Chr 12:32), suggesting wisdom alongside material blessing.</p>",
"27": "<p>From Asher: Ahihud son of Shelomi. Asher's coastal territory in the northern Galilee would be associated with maritime trade. The prophetess Anna (Luke 2:36) was from Asher — the tribe persisting to the New Testament era.</p>",
"28": "<p>From Naphtali: Pedahel son of Ammihud. Naphtali's territory alongside the Sea of Galilee becomes the heartland of Jesus's early ministry (Matt 4:15). The 'land of Naphtali' that Isaiah promised light to (Isa 9:1) receives its fulfillment in the one who is the light of the world.</p>",
"29": "<p>These are the men whom YHWH commanded to apportion the inheritance to Israel in the land of Canaan. The chapter closes with the full list named. The inheritance is not an abstraction — it has named recipients, named boundaries, and named administrators. The promise is taking concrete form at the threshold of its realization.</p>"
},
"35": {
"1": "<p>On the plains of Moab by the Jordan at Jericho, YHWH speaks to Moses concerning the Levites. The Levites receive no tribal territory (ch18:20-24 established this) but must live somewhere. Their provision is the subject of this chapter.</p>",
"2": "<p>'Command the Israelites to give the Levites from their hereditary possession cities to live in, and pasture lands (<em>migrashim</em>) around the cities for their livestock.' <em>Migrash</em> (pasture land) describes the ring of open ground around each city — a buffer between city and field. The Levites are given cities scattered throughout all tribal territories.</p>",
"3": "<p>The cities shall be for the Levites to live in, and the pastureland for their livestock, their possessions, and all their animals. The Levites' provision is practical and complete — housing and land for their herds, drawn from each tribe's own inheritance. The priesthood is embedded in the community, not isolated from it.</p>",
"4": "<p>The pastureland around the cities shall extend one thousand cubits in each direction from the city wall. The standardized measurement ensures every Levitical city has identical surrounding pasture, regardless of which tribe hosts them — equality of provision across the land.</p>",
"5": "<p>Two thousand cubits are measured on each side — east, south, west, and north — with the city in the center. The city sits at the center of a 4,000-cubit square of pastureland. Precision here matters: the Levites' portion is carefully measured, not approximate. God's provision is exact.</p>",
"6": "<p>Six of the forty-eight Levitical cities shall be cities of refuge (<em>arei miklat</em>), where the manslayer may flee. The cities of refuge are Levitical — administered by those who mediate between God and people. This is not coincidental: those who serve at the altar also serve as mediators of justice and mercy for those who shed blood accidentally.</p>",
"7": "<p>Forty-eight cities in total shall be given to the Levites. Forty-eight from a nation of twelve tribes means four cities per tribe on average. The Levites are distributed throughout Israel — present in every region, serving every part of the people. Numbers 35:7 realizes the 'scattered in Israel' dimension of Jacob's prophecy about Simeon and Levi (Gen 49:7), but transformed from curse to vocation.</p>",
"8": "<p>The cities shall be given from the possessions of the Israelites: from the larger tribes, more; from the smaller, fewer. Each gives proportionally. The principle of proportional giving — from whom much is given, much is required — is embedded in the land distribution itself.</p>",
"9": "<p>YHWH speaks: 'Speak to the Israelites and say to them: When you cross the Jordan into Canaan...' The cities of refuge regulation begins with the crossing as the reference point. The institution is for life in the land — it presupposes settlement, community, and the possibility of accidental death among neighbors.</p>",
"10": "<p>'...you shall designate cities to be cities of refuge for you.' <em>Miklat</em> (refuge/asylum) derives from a root meaning to receive or gather in. The city 'receives' the person fleeing. The image is of a place that takes in the otherwise condemned — a sanctuary.</p>",
"11": "<p>Three cities east of the Jordan and three west, giving six total. The arrangement ensures no one in the land is more than a day's journey from a city of refuge. The institution was designed for accessibility — mercy should be reachable before the blood avenger (<em>goel haddam</em>) catches up.</p>",
"12": "<p>These cities are a refuge from the blood avenger (<em>goel haddam</em>), so the manslayer shall not die until he stands before the congregation (<em>edah</em>) for trial. <em>Goel haddam</em> — literally 'redeemer of the blood' — is the nearest kinsman whose duty is to avenge a killed relative. The same word <em>goel</em> describes the kinsman-redeemer of Ruth. Justice and mercy share the same vocabulary.</p>",
"13": "<p>Six cities of refuge for all Israel, giving access across the whole land. The repetition of 'six' and their placement east and west (v14-15) underscores that the institution is universal — not just for one tribe or region but for any person anywhere in Israel's territory.</p>",
"14": "<p>Three cities across the Jordan and three in Canaan — these shall be cities of refuge. Moses himself designates the three east-Jordan cities before his death (Deut 4:41-43). Joshua designates the three west-Jordan cities (Josh 20:7-8). Two leaders, one institution — its establishment spans the transition of leadership.</p>",
"15": "<p>'These six cities shall be a refuge for the Israelites, for the resident alien, and for the sojourner among them.' The cities of refuge are not for Israelites only — <em>ger</em> (sojourner, resident alien) and <em>toshav</em> (temporary dweller) are also covered. Mercy is not ethnically restricted; the institution extends to all who live under Israel's covenant order.</p>",
"16": "<p>But if someone strikes with an iron instrument and the victim dies, it is murder (<em>ratzach</em>); the murderer shall be put to death. The distinction between murder and manslaughter begins here with intent inferred from weapon: iron instruments were tools of deliberate killing, not accidental death.</p>",
"17": "<p>Striking with a stone that can kill, if death results — this is murder; the murderer shall be put to death. The blood avenger shall put the murderer to death when he meets him. The law requires death for intentional killing; it does not leave vengeance to individual passion alone but channels it through defined roles.</p>",
"18": "<p>Likewise if struck with a wooden weapon capable of killing — it is murder; the murderer shall be put to death. The progression through iron, stone, and wood exhausts the categories of hand weapons. Intent, not merely the act, determines guilt — but intent is inferred from the capacity of the weapon used.</p>",
"19": "<p>The blood avenger shall himself put the murderer to death — when he meets him, he shall put him to death. The blood avenger acts as the community's agent of retributive justice, not as a private vigilante. His role is legitimate and expected within the legal structure.</p>",
"20": "<p>If the killing was from enmity — if someone pushed another from hatred, or threw something at them deliberately, and they died — it is murder. Intent revealed through prior relationship and manner of attack determines guilt. The law sees through physical act to motive.</p>",
"21": "<p>Striking from hostility so that death results — the striker is a murderer and shall be put to death by the blood avenger when he meets him. No city of refuge protects the intentional killer. The refuge is for the innocent-in-intent, not the guilty.</p>",
"22": "<p>'But if someone pushed another suddenly without enmity, or threw anything at them unintentionally...' — the shift to accidental killing begins with relational and circumstantial evidence. No prior hostility, no malicious forethought — the act was sudden and unforeseen.</p>",
"23": "<p>...or if without seeing someone a stone was dropped on them that could kill, and they died — and the person was not their enemy and did not seek their harm — then the congregation shall judge. Community discernment determines the boundary between murder and manslaughter. No individual makes this determination alone.</p>",
"24": "<p>The congregation shall judge between the manslayer and the blood avenger according to these regulations. The congregation serves as tribunal — not the avenger, not the accused. The community's collective judgment protects against both unchecked revenge and unchecked impunity.</p>",
"25": "<p>The congregation shall rescue the manslayer from the blood avenger and return him to the city of refuge. He shall live there until the death of the high priest (<em>kohen hagadol</em>) who was anointed with holy oil. This is the pivot of the chapter: the high priest's death is the mechanism of the manslayer's release.</p>",
"26": "<p>If the manslayer goes outside the limits of the city of refuge and the blood avenger finds and kills him — no blood guilt attaches to the avenger. The protection is conditional on remaining within the city. Outside its boundaries, the manslayer is exposed. The refuge only protects those who stay within it.</p>",
"27": "<p>For the manslayer must remain in his city of refuge until the death of the high priest; after the high priest's death he may return to his ancestral land. The high priest's death is the only lawful exit. This is a remarkable provision: the manslayer's freedom is bound to the life of the high priest. When the high priest dies, the manslayer goes free.</p>",
"28": "<p>These shall be your statutes (<em>chukat mishpat</em>) for all your generations throughout all your settlements. The cities of refuge institution is permanent law, not a temporary arrangement for the wilderness period.</p>",
"29": "<p>Whoever kills a person — the murderer shall be put to death on the testimony of witnesses (<em>edim</em>). But no one shall be put to death on the testimony of only one witness. Two witnesses minimum for a capital verdict — protecting against false accusation and personal revenge framed as justice.</p>",
"30": "<p>You shall not accept a ransom (<em>kofer</em>) for the life of a murderer who is guilty of death; he shall be put to death. <em>Kofer</em> (ransom/substitute payment) is explicitly prohibited in murder cases. Life cannot be ransomed with money — only blood answers for blood. The prohibition reinforces the weight of human life made in God's image.</p>",
"31": "<p>And you shall not accept a ransom for one who has fled to a city of refuge, allowing them to return to live in the land before the death of the high priest. The two prohibitions together — no ransom for murderers (v30), no ransom to shorten the manslayer's exile (v31) — seal the system. Money cannot buy its way around either judgment or mercy's timeline.</p>",
"32": "<p>'You shall not pollute the land in which you live, for blood pollutes the land, and no atonement (<em>kapparah</em>) can be made for the land for the blood shed in it, except by the blood of the one who shed it.' The land itself is a moral entity — it can be defiled (<em>tamei</em>) and it can receive atonement (<em>kapparah</em>). The same vocabulary used for ritual purity is applied to civic justice.</p>",
"33": "<p>You shall not defile the land where you live and in the midst of which I dwell, for I, YHWH, dwell in the midst of the Israelites. The ultimate reason for these careful laws is YHWH's presence: <em>ani YHWH shokhen betoch</em> — I YHWH dwell in the midst. Where God dwells, the land must be kept clean. Justice is not merely civic — it is theological. A defiled land cannot hold a holy God.</p>",
"34": "<p>The chapter closes returning to the theological center: the land belongs to YHWH; Israel merely sojourns in it. The cities of refuge, the witnesses requirement, the prohibition on ransom — all derive from this reality. Justice in the land reflects the character of the one who inhabits it.</p>"
},
"36": {
"1": "<p>The heads of the fathers' clans of the family of Manasseh son of Joseph come before Moses and the leaders. The case concerns the daughters of Zelophehad (raised first in ch27:1-11). Their right to inherit has been established — now a consequence of that ruling surfaces that requires further adjudication.</p>",
"2": "<p>They report: 'YHWH commanded our lord to give the land as inheritance by lot to the Israelites, and our lord was commanded by YHWH to give the inheritance of our brother Zelophehad to his daughters.' The leaders do not dispute the ruling — they accept it — but they see a problem flowing from it.</p>",
"3": "<p>'But if they marry into another Israelite tribe, their inheritance will be taken from our ancestral inheritance and added to the inheritance of the tribe into which they marry; so it will be taken away from our allotted inheritance.' At the jubilee, inherited land returns to its tribe — but if a woman from one tribe marries into another, her land goes with her marriage and never returns to the original tribe.</p>",
"4": "<p>When the jubilee of the Israelites comes, their inheritance will be added to the inheritance of the tribe into which they have married; so it will be taken from our ancestral tribe's inheritance. <em>Yovel</em> (jubilee) — the fifty-year reset (Lev 25) — would normally return land. But marriage creates a permanent tribal transfer that the jubilee cannot undo. The daughters' inheritance creates a structural tension in the land distribution system.</p>",
"5": "<p>Moses commands by YHWH's word: 'The tribe of Joseph's sons is right.' YHWH vindicates the complaint. The daughters' inheritance is legitimate; the concern about tribal land loss is also legitimate. Both rulings can stand together — a supplemental regulation resolves the tension without overturning either.</p>",
"6": "<p>'This is what YHWH commands concerning the daughters of Zelophehad: let them marry whom they think best, but they shall marry only within the clan of their father's tribe.' Full freedom of choice within the constraint of tribal endogamy. The daughters are not coerced into a specific marriage — only required to marry within Manasseh. The narrowest restriction that preserves both inheritance rights and tribal integrity.</p>",
"7": "<p>'So no inheritance of the Israelites shall transfer from tribe to tribe; for all Israelites shall retain the inheritance of their ancestral tribe.' The principle behind the ruling: tribal land allocations are permanent. The jubilee system (Lev 25) and this endogamy requirement together create a land distribution that resists alienation — God's gift to each tribe stays with each tribe.</p>",
"8": "<p>'Every daughter who possesses an inheritance in any tribe of the Israelites shall marry one from the clan of her father's tribe, so that all Israelites may retain their ancestral inheritance.' The ruling generalizes beyond Zelophehad's daughters — it becomes standing law for any woman who inherits. The case becomes precedent.</p>",
"9": "<p>'No inheritance shall transfer from one tribe to another; each of the tribes of Israel shall retain its own inheritance.' The repetition reinforces the principle's permanence and centrality. Land, inheritance, tribe, and identity are interlocked in the Mosaic vision of the land. This is not mere property law — it is a vision of a nation where every family has a stake in the land, a stake that can be recovered and cannot be permanently lost.</p>",
"10": "<p>The daughters of Zelophehad did as YHWH commanded Moses. The text names their obedience before recounting it — their compliance is the point. Mahlah, Tirzah, Hoglah, Milcah, and Noah are named individuals, not anonymous women subsumed into a ruling. Scripture preserves their names.</p>",
"11": "<p>Mahlah, Tirzah, Hoglah, Milcah, and Noah married sons of their father's brothers — within the clans of Manasseh. Five women, each making the same choice: to obey and marry within their tribe. Their obedience is collective and complete. The jubilee question is resolved not by coercion but by faithful compliance.</p>",
"12": "<p>Their inheritance remained in the tribe of their father's clan. The outcome of their obedience is stated simply: the inheritance stayed. The purpose of the ruling is achieved. The land of Zelophehad — fought for by his daughters (ch27), now preserved by their marriages — remains within Manasseh.</p>",
"13": "<p>'These are the commandments and the regulations which YHWH commanded through Moses to the Israelites in the plains of Moab by the Jordan at Jericho.' The closing verse gathers all of Numbers 28–36 under one summary and anchors the entire book at a specific place and moment: the plains of Moab, east of the Jordan, facing Jericho. Israel stands at the threshold. The book of Numbers ends not with an arrival but with a readiness — the people poised to enter what all these laws have been preparing them for.</p>"
}
}

comm = load_comm('mkt-original', 'numbers')
merge_comm(comm, ORIGINAL)
save_comm('mkt-original', 'numbers', comm)
print('Numbers 34-36 mkt-original written.')
